#!/usr/bin/env node
/**
 * Generate `.vscode/lattice.code-snippets` from `lib/components/*.json`.
 *
 * One snippet per layout. Prefix is `lattice-<name>` so authors type
 * `lattice-` in any .md file and VS Code suggests every component;
 * tab inserts the canonical markdown skeleton.
 *
 *   node tools/build-snippets.js           # write the snippets file
 *   node tools/build-snippets.js --check   # exit 1 if committed file is stale
 *   npm run snippets:build                 # alias for write mode
 *
 * The generated file is committed. Re-run after touching any
 * `lib/components/*.json` so the snippets stay in lockstep with
 * the manifests; CI runs --check to enforce this.
 *
 * See design/design-system.md §7 for the discovery model.
 */

const fs = require('node:fs');
const path = require('node:path');
const { loadAll } = require('../lib/components');

const ROOT = path.join(__dirname, '..');
const OUT_DIR = path.join(ROOT, '.vscode');
const OUT_FILE = path.join(OUT_DIR, 'lattice.code-snippets');

const HEADER = [
  '// Lattice slide-layout snippets. Generated by tools/build-snippets.js',
  '// from lib/components/*.json. Do not edit by hand — re-run `npm run',
  '// snippets:build` after touching any manifest. CI gate: `npm run',
  '// snippets:build -- --check`.',
  '',
].join('\n');

/**
 * Return the VS Code snippet object derived from the current manifests.
 * Pure: takes no I/O, just transforms loaded manifests into snippet shape.
 */
function buildSnippets(manifests) {
  const list = manifests || loadAll();
  const out = {};
  for (const m of list) {
    out[`lattice: ${m.name}`] = {
      prefix: `lattice-${m.name}`,
      body: m.skeleton.replace(/\n$/, '').split('\n'),
      description: m.description,
    };
  }
  return out;
}

/**
 * Serialize the snippet object to the canonical file text — header
 * comment + 2-space-indented JSON + trailing newline. Stable enough to
 * diff against the committed file.
 */
function serialize(snippets) {
  return `${HEADER}${JSON.stringify(snippets, null, 2)}\n`;
}

function writeFile(text) {
  if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });
  fs.writeFileSync(OUT_FILE, text);
}

function readCommitted() {
  if (!fs.existsSync(OUT_FILE)) return null;
  return fs.readFileSync(OUT_FILE, 'utf8');
}

function main(argv) {
  const check = argv.includes('--check');
  const fresh = serialize(buildSnippets());
  if (check) {
    const current = readCommitted();
    if (current === fresh) {
      process.stdout.write(`${OUT_FILE} is up to date.\n`);
      return 0;
    }
    process.stderr.write(`error: ${OUT_FILE} is stale.\n`);
    process.stderr.write('       Run `npm run snippets:build` to regenerate.\n');
    return 1;
  }
  writeFile(fresh);
  process.stdout.write(`wrote ${OUT_FILE} (${Object.keys(buildSnippets()).length} snippets)\n`);
  return 0;
}

if (require.main === module) {
  process.exit(main(process.argv.slice(2)));
}

module.exports = { buildSnippets, serialize, main, OUT_FILE };
